class Solution:
    def countArrays(self, original, bounds):
        base = original[0]
        lo = -(10 ** 18)
        hi = 10 ** 18
        for i in range(len(original)):
            offset = original[i] - base
            lo = max(lo, bounds[i][0] - offset)
            hi = min(hi, bounds[i][1] - offset)
        return max(0, hi - lo + 1)

