class Solution:
    def countArrays(self, original, bounds):
        n = len(original)
        lo, hi = bounds[0][0], bounds[0][1]
        for i in range(1, n):
            diff = original[i] - original[i - 1]
            lo += diff
            hi += diff
            lo = max(lo, bounds[i][0])
            hi = min(hi, bounds[i][1])
            if lo > hi:
                return 0
        return hi - lo + 1

