var countArrays = function(original, bounds) {
    const n = original.length;
    let lo = bounds[0][0];
    let hi = bounds[0][1];
    for (let i = 1; i < n; i++) {
        const diff = original[i] - original[i - 1];
        lo += diff;
        hi += diff;
        lo = Math.max(lo, bounds[i][0]);
        hi = Math.min(hi, bounds[i][1]);
        if (lo > hi) return 0;
    }
    return hi - lo + 1;
};
